type ReservationDetails struct {
	Date      string
	TableNum  int
}

func manageReservations(reservations map[string][]ReservationDetails, name string, date string, tableNum int, action string) (map[string][]ReservationDetails, error) {
	switch action {
	case "add":
		for _, res := range reservations {
			for _, detail := range res {
				if detail.Date == date && detail.TableNum == tableNum {
					return reservations, fmt.Errorf("table %d is already booked on %s", tableNum, date)
				}
			}
		}
		reservations[name] = append(reservations[name], ReservationDetails{Date: date, TableNum: tableNum})
	case "cancel":
		if _, exists := reservations[name]; !exists {
			return reservations, fmt.Errorf("no reservations found for %s", name)
		}
		var updatedDetails []ReservationDetails
		for _, detail := range reservations[name] {
			if detail.Date != date || detail.TableNum != tableNum {
				updatedDetails = append(updatedDetails, detail)
			}
		}
		if len(updatedDetails) == 0 {
			delete(reservations, name)
		} else {
			reservations[name] = updatedDetails
		}
	default:
		return reservations, fmt.Errorf("invalid action: %s", action)
	}
	return reservations, nil
}
