func (tm *TaskManager) InsertTaskAtPosition(task Task, position int) {
	if position < 0 || position > tm.tasks.Len() {
		return // or handle error
	}

	var mark *list.Element
	if position == 0 {
		mark = tm.tasks.Front()
	} else if position == tm.tasks.Len() {
		mark = nil // insert before nil means append
	} else {
		mark = tm.tasks.Front()
		for i := 0; i < position; i++ {
			mark = mark.Next()
		}
	}

	if mark == nil {
		tm.tasks.PushBack(task)
	} else {
		tm.tasks.InsertBefore(task, mark)
	}
}

func (tm *TaskManager) RemoveTaskByIndex(index int) {
	if index < 0 || index >= tm.tasks.Len() {
		return // or handle error
	}

	element := tm.tasks.Front()
	for i := 0; i < index; i++ {
		element = element.Next()
	}

	tm.tasks.Remove(element)
