import java.util.*;

public class SocialNetwork {
    private Map<String, List<String>> userFollowers; // Key: user, Value: list of followers
    private List<String> followEvents; // Chronological record of follow events

    public SocialNetwork() {
        userFollowers = new HashMap<>();
        followEvents = new ArrayList<>();
    }

    // Add a follow relationship
    public void follow(String follower, String followee) {
        if (!userFollowers.containsKey(followee)) {
            userFollowers.put(followee, new ArrayList<>());
        }
        userFollowers.get(followee).add(follower);
        followEvents.add(follower + " followed " + followee);
    }

    // Find the latest common follower between two users
    public String findLatestCommonFollower(String user1, String user2) {
        List<String> followers1 = userFollowers.getOrDefault(user1, new ArrayList<>());
        List<String> followers2 = userFollowers.getOrDefault(user2, new ArrayList<>());
        Set<String> commonFollowers = new HashSet<>(followers1);
        commonFollowers.retainAll(followers2);

        for (int i = followEvents.size() - 1; i >= 0; i--) {
            String[] parts = followEvents.get(i).split(" followed ");
            String follower = parts[0];
            String followee = parts[1];
            if (commonFollowers.contains(follower) && 
                (followee.equals(user1) || followee.equals(user2))) {
                return follower;
            }
        }
        return null;
    }

    // Suggest possible new friends through mutual connections
    public List<String> suggestFriends(String user) {
        List<String> suggestions = new ArrayList<>();
        List<String> followers = userFollowers.getOrDefault(user, new ArrayList<>());
        Map<String, Integer> mutualCount = new HashMap<>();

        for (String follower : followers) {
            List<String> followerFollowees = userFollowers.getOrDefault(follower, new ArrayList<>());
            for (String followee : followerFollowees) {
                if (!followee.equals(user) && !followers.contains(followee)) {
                    mutualCount.put(followee, mutualCount.getOrDefault(followee, 0) + 1);
                }
            }
        }

        for (Map.Entry<String, Integer> entry : mutualCount.entrySet()) {
            if (entry.getValue() >= 2) { // At least 2 mutual connections
                suggestions.add(entry.getKey());
            }
        }
        return suggestions;
    }
}
